// Extract access_token","    if (jsonData.access_token) {",'        pm.environment.set("access_token", jsonData.access_token);','        console.log("✅ Access token received (OAuth 2.0 - Client Credentials Basic)");',"    }","    ","    // Extract token metadata","    if (jsonData.token_type) {",'        pm.environment.set("token_type", jsonData.token_type);',"    }","    if (jsonData.expires_in) {","        const expiresAt = Date.now() + (jsonData.expires_in * 1000);",'        pm.environment.set("access_token_expires_at", expiresAt.toString());','        console.log("⏱️ Access token expires in:", jsonData.expires_in, "seconds (" + Math.round(jsonData.expires_in / 60) + " minutes)");',"    }","    if (jsonData.scope) {",'        pm.environment.set("token_scope", jsonData.scope);','        console.log("📋 Token scope:", jsonData.scope);',"    }","    ","    // Note: OAuth 2.0 Client Credentials does not return id_token or refresh_token",'    console.log("✅ Client Credentials flow completed successfully (Basic Auth)!");',"} else {",'    console.log("❌ Client Credentials token request failed:", pm.response.code);',"    try {","        const jsonData = pm.response.json();","        if (jsonData.error) {",'            console.log("   Error:", jsonData.error);',"            if (jsonData.error_description) {",'                console.log("   Description:", jsonData.error_description);',"            }","            ","            // Common errors",'            if (jsonData.error === "invalid_client") {','                console.log("   💡 Tip: Verify user_client_id and user_client_secret in Authorization header are correct");','                console.log("   💡 Tip: Verify {{user_client_credentials_basic}} = base64(user_client_id:user_client_secret)");','            } else if (jsonData.error === "invalid_scope") {','                console.log("   💡 Tip: Verify requested scopes are valid for this client");',"            }","        }","    } catch (e) {","        // Response may not be JSON","    }","}"],type:"text/javascript"}}]}]}),o.push({name:"Device Code Flow",item:[{name:"1. Request Device Authorization",request:{method:"POST",header:[{key:"Content-Type",value:"application/x-www-form-urlencoded"},{key:"Accept",value:"application/json"}],body:{mode:"urlencoded",urlencoded:[{key:"client_id",value:"{{user_client_id}}"},{key:"scope",value:"{{scopes_oauth2}}"}]},url:dt(`${t}/as/device_authorization`),description:"**Device Code Flow - OAuth 2.0 (RFC 8628)**\n\n**Educational Context:**\n- For devices without browsers (TVs, printers, IoT)\n- Returns device_code (for polling), user_code (for user to enter), and verification_uri\n- User enters user_code at verification_uri on another device\n- OAuth 2.0: Returns access_token only (no id_token)\n- Device code expires after expires_in seconds (typically 900 seconds = 15 minutes)\n- Poll token endpoint at interval seconds (typically 5 seconds) until user authorizes"},event:[{listen:"test",script:{exec:["// Extract all Device Code Flow response values","if (pm.response.code === 200) {","    const jsonData = pm.response.json();","    ","    // Required: device_code for polling","    if (jsonData.device_code) {",'        pm.environment.set("device_code", jsonData.device_code);','        console.log("✅ Device code saved:", jsonData.device_code.substring(0, 20) + "...");',"    }","    ","    // Required: user_code for user to enter","    if (jsonData.user_code) {",'        pm.environment.set("user_code", jsonData.user_code);','        console.log("✅ User code saved:", jsonData.user_code);','        console.log("   👤 User must enter this code at verification URI");',"    }","    ","    // Required: verification_uri where user enters code","    if (jsonData.verification_uri) {",'        pm.environment.set("verification_uri", jsonData.verification_uri);','        console.log("✅ Verification URI:", jsonData.verification_uri);',"    }","    ","    // Optional: verification_uri_complete (includes user_code, for QR codes)","    if (jsonData.verification_uri_complete) {",'        pm.environment.set("verification_uri_complete", jsonData.verification_uri_complete);','        console.log("✅ Verification URI Complete (QR code):", jsonData.verification_uri_complete);',"    }","    ","    // Required: expires_in (device code expiration in seconds, typically 900)","    if (jsonData.expires_in) {",'        pm.environment.set("device_code_expires_in", jsonData.expires_in.toString());',"        const expiresAt = Date.now() + (jsonData.expires_in * 1000);",'        pm.environment.set("device_code_expires_at", expiresAt.toString());','        console.log("⏱️ Device code expires in:", jsonData.expires_in, "seconds (" + Math.round(jsonData.expires_in / 60) + " minutes)");',"    }","    ","    // Required: interval (polling interval in seconds, typically 5)","    const interval = jsonData.interval || 5;",'    pm.environment.set("device_code_interval", interval.toString());','    console.log("🔄 Poll token endpoint every", interval, "seconds");','    console.log("");','    console.log("📋 Next Steps:");','    console.log("   1. User opens:", pm.environment.get("verification_uri") || jsonData.verification_uri);','    console.log("   2. User enters code:", pm.environment.get("user_code") || jsonData.user_code);','    console.log("   3. User authenticates and authorizes");','    console.log("   4. Call Poll for Tokens step (wait", interval, "seconds between polls)");',"} else {",'    console.log("❌ Device authorization request failed:", pm.response.code);',"    try {","        const jsonData = pm.response.json();","        if (jsonData.error) {",'            console.log("   Error:", jsonData.error);',"            if (jsonData.error_description) {",'                console.log("   Description:", jsonData.error_description);',"            }","        }","    } catch (e) {","        // Response may not be JSON","    }","}"],type:"text/javascript"}}]},{name:"2. Poll for Tokens",request:{method:"POST",header:[{key:"Content-Type",value:"application/x-www-form-urlencoded"},{key:"Accept",value:"application/json"}],body:{mode:"urlencoded",urlencoded:[{key:"grant_type",value:"urn:ietf:params:oauth:grant-type:device_code"},{key:"device_code",value:"{{device_code}}"},{key:"client_id",value:"{{user_client_id}}"}]},url:dt(`${t}/as/token`),description:"**Poll for Tokens - Device Code Flow (OAuth 2.0)**\n\n**Educational Context:**\n- Poll this endpoint until user authorizes the device\n- Use interval from device authorization response (typically 5 seconds) - wait between polls\n- Handle responses:\n  - 200 OK: User authorized - extract access_token\n  - 400 Bad Request with error=authorization_pending: User has not authorized yet - keep polling\n  - 400 Bad Request with error=slow_down: Poll too frequently - increase interval by 5 seconds\n  - 400 Bad Request with error=expired_token: Device code expired - restart flow\n  - 400 Bad Request with error=access_denied: User denied authorization - restart flow\n- OAuth 2.0: Returns access_token only (no id_token)\n- Refresh token available if requested in scope"},event:[{listen:"test",script:{exec:["// Handle Device Code Flow polling responses","if (pm.response.code === 200) {","    // Success: User authorized, extract tokens","    const jsonData = pm.response.json();","    ","    // OAuth 2.0: Extract access_token only (no id_token)","    if (jsonData.access_token) {",'        pm.environment.set("access_token", jsonData.access_token);','        console.log("✅ Access token received (OAuth 2.0 - no id_token)");',"    }","    ","    // Extract token metadata","    if (jsonData.token_type) {",'        pm.environment.set("token_type", jsonData.token_type);',"    }","    if (jsonData.expires_in) {","        const expiresAt = Date.now() + (jsonData.expires_in * 1000);",'        pm.environment.set("access_token_expires_at", expiresAt.toString());','        console.log("⏱️ Access token expires in:", jsonData.expires_in, "seconds");',"    }","    if (jsonData.scope) {",'        pm.environment.set("token_scope", jsonData.scope);',"    }","    ","    // Note: OAuth 2.0 Device Code Flow does not return refresh_token or id_token",'    console.log("✅ Device Code Flow completed successfully!");',"} else if (pm.response.code === 400) {","    // Handle polling errors","    const jsonData = pm.response.json();","    ",'    if (jsonData.error === "authorization_pending") {','        console.log("⏳ Authorization pending - user has not authorized yet");','        console.log("   🔄 Poll again after interval (typically 5 seconds)");','        const interval = parseInt(pm.environment.get("device_code_interval") || "5");','        console.log("   ⏱️ Wait", interval, "seconds before next poll");','    } else if (jsonData.error === "slow_down") {','        console.log("⚠️ Slow down - polling too frequently");','        const currentInterval = parseInt(pm.environment.get("device_code_interval") || "5");',"        const newInterval = currentInterval + 5;",'        pm.environment.set("device_code_interval", newInterval.toString());','        console.log("   🔄 Increased polling interval to", newInterval, "seconds");','    } else if (jsonData.error === "expired_token") {','        console.log("❌ Device code expired - restart flow from Request Device Authorization step");','        pm.environment.unset("device_code");','        pm.environment.unset("user_code");','    } else if (jsonData.error === "access_denied") {','        console.log("❌ User denied authorization - restart flow from Request Device Authorization step");','        pm.environment.unset("device_code");','        pm.environment.unset("user_code");',"    } else {",'        console.log("❌ Polling failed:", jsonData.error);',"        if (jsonData.error_description) {",'            console.log("   Description:", jsonData.error_description);',"        }","    }","} else {",'    console.log("❌ Unexpected response code:", pm.response.code);',"}"],type:"text/javascript"}}]}]}),o.push({name:"Implicit Flow (URL Fragment)",item:[{name:"1. Build Authorization URL",request:{method:"GET",url:dt(`${t}/as/authorize?client_id={{user_client_id}}&response_type=token&redirect_uri={{redirect_uri}}&scope={{scopes_oauth2}}&state={{state}}&response_mode=fragment`)},description:"**Implicit Flow - OAuth 2.0 (URL Fragment)**\n\n**Educational Context:**\n- OAuth 2.0 Implicit flow (deprecated in OAuth 2.1, but still part of OAuth 2.0)\n- Tokens returned directly in URL fragment (not secure)\n- OAuth 2.0: Returns access_token only (response_type=token, no id_token)\n- No refresh_token (use Authorization Code flow instead)\n- response_mode=fragment is the default for implicit flow\n- ⚠️ Deprecated in OAuth 2.1 for security reasons",event:[{listen:"test",script:{exec:["// Note: In real OAuth 2.0 Implicit flow, access_token comes in redirect URL fragment","// This is a placeholder - actual token extraction happens from callback URL","// Example callback URL: https://example.com/callback#access_token=...&token_type=Bearer&expires_in=3600&state=...","if (pm.response.code === 200 || pm.response.code === 302) {",'    console.log("✅ Authorization URL generated for OAuth 2.0 Implicit Flow");','    console.log("⚠️ Access token will be in redirect URL fragment, not in response body");',"}"],type:"text/javascript"}}]}]}),o.push({name:"Implicit Flow (Form POST)",item:[{name:"1. Build Authorization URL",request:{method:"GET",url:dt(`${t}/as/authorize?client_id={{user_client_id}}&response_type=token&redirect_uri={{redirect_uri}}&scope={{scopes_oauth2}}&state={{state}}&response_mode=form_post`)},description:"**Implicit Flow - OAuth 2.0 (Form POST)**\n\n**Educational Context:**\n- OAuth 2.0 Implicit flow with form_post response mode\n- More secure than fragment (no tokens in URL)\n- OAuth 2.0: Returns access_token only (response_type=token, no id_token)\n- Tokens sent via HTTP POST as form data\n- Requires server-side form processing\n- ⚠️ Deprecated in